meta_by_id={m['id']:m for m in meta}
for mod in modules:
    mod.update(meta_by_id[mod['id']])

out = Path('insulin-education-app/src/data.js')
out.parent.mkdir(parents=True, exist_ok=True)
out.write_text('export const modules = ' + json.dumps(modules, ensure_ascii=False, indent=2) + ';\n\nexport const appSources = [\n  { label: "ADA Standards of Care 2026", url: "https://professional.diabetes.org/standards-of-care" },\n  { label: "IDF Type 2 Diabetes Recommendations 2025", url: "https://idf.org/what-we-do/education/idf-clinical-practice-recommendations-for-type-2-diabetes-2025/" },\n  { label: "International DKA Consensus 2024", url: "https://doi.org/10.2337/dci24-0032" },\n  { label: "Endocrine Society / ESE Pregnancy Guidance", url: "https://www.endocrine.org/clinical-practice-guidelines/preexisting-diabetes-in-pregnancy" },\n  { label: "KDIGO Diabetes in CKD", url: "https://kdigo.org/guidelines/diabetes-ckd/" },\n  { label: "IWGDF Foot Guidelines", url: "https://iwgdfguidelines.org/" }\n];\n', encoding='utf-8')
print('wrote', out, 'modules', len(modules), 'qas', sum(len(m['qas']) for m in modules))
